module decoder_2to4(in, decoded_out);

    input [1:0] in;
    output [3:0] decoded_out;
    reg [3:0] decoded_out;

    always @(in)
        case (in)
            2'b00: decoded_out = 4'b0001;
            2'b01: decoded_out = 4'b0010;
            2'b10: decoded_out = 4'b0100;
            2'b11: decoded_out = 4'b1000;
        endcase

endmodule
